eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   PROFILE_ABOUT: () => (/* binding */ PROFILE_ABOUT),\n/* harmony export */   PROFILE_IMAGES: () => (/* binding */ PROFILE_IMAGES),\n/* harmony export */   PROFILE_SUBTITLE: () => (/* binding */ PROFILE_SUBTITLE),\n/* harmony export */   PROFILE_TAGLINE: () => (/* binding */ PROFILE_TAGLINE)\n/* harmony export */ });\n/** Image paths extracted from Reliable Company Profile PDF */ const PROFILE_IMAGES = {\n    hero: \"/profile/page-2-img-1.jpeg\",\n    expertise: \"/profile/page-3-img-1.jpeg\",\n    feed: \"/profile/page-4-img-1.jpeg\",\n    pmc: \"/profile/page-6-img-1.jpeg\",\n    designManagement: \"/profile/page-8-img-1.jpeg\",\n    procurement: \"/profile/page-10-img-1.jpeg\",\n    programManagement: \"/profile/page-12-img-1.jpeg\",\n    construction: \"/profile/page-14-img-1.jpeg\",\n    commissioning: \"/profile/page-16-img-1.jpeg\",\n    operations: \"/profile/page-18-img-1.jpeg\",\n    optimization: \"/profile/page-20-img-1.jpeg\",\n    industries: \"/profile/page-24-img-1.jpeg\",\n    industriesGrid: \"/profile/page-25-img-1.jpeg\",\n    contact: \"/profile/page-26-img-1.jpeg\"\n};\nconst PROFILE_TAGLINE = \"Professional Cyber Security & Penetration Testing\";\nconst PROFILE_SUBTITLE = \"Cyber Security & VAPT\";\nconst PROFILE_ABOUT = `Reliable Company is a specialized cybersecurity services group providing Vulnerability Assessment and Penetration Testing (VAPT), web application security testing, network security assessment, and cybersecurity consulting across Saudi Arabia. As a group of companies, we started our operations in 2016 from UAE and in 2023 we expanded our business in the Kingdom of Saudi Arabia.\r\n\r\nOur management team has 100+ years of combined experience securing industrial and enterprise environments across Desalination, Oil & Gas, Water Infrastructure, Manufacturing, and critical infrastructure sectors. Passion for quality, innovative security methodologies, and hands-on testing experience are the qualities that make our team unique in delivering real-world protection.\r\n\r\nOur certified security professionals are committed to identifying vulnerabilities before attackers do — protecting applications, networks, cloud environments, and industrial systems with rigorous testing and actionable remediation guidance.`;\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/lib/profile-content.ts\n");

